begin;create table if not exists public.lead_qualification_profiles(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,lead_id uuid not null references public.leads(id)on delete cascade,broker_id uuid not null references public.profiles(id)on delete restrict,version int not null default 1,purpose_key text,timeline_key text,financing_key text,budget_readiness_key text,region_readiness_key text,unit_profile_key text,decision_role_key text,contact_preference_key text,answered_count int not null default 0,completed_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(organization_id,lead_id));create table if not exists public.lead_qualification_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,lead_id uuid not null references public.leads(id)on delete cascade,profile_id uuid not null references public.lead_qualification_profiles(id)on delete cascade,broker_id uuid not null references public.profiles(id),changed_fields text[]not null,source text not null default'broker_confirmation',created_at timestamptz not null default now());alter table public.lead_qualification_profiles enable row level security;alter table public.lead_qualification_events enable row level security;create policy lead_qualification_profiles_scope on public.lead_qualification_profiles for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));create policy lead_qualification_events_scope on public.lead_qualification_events for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));revoke all on public.lead_qualification_profiles,public.lead_qualification_events from anon;revoke insert,update,delete on public.lead_qualification_profiles,public.lead_qualification_events from authenticated;grant select on public.lead_qualification_profiles,public.lead_qualification_events to authenticated;grant all on public.lead_qualification_profiles,public.lead_qualification_events to service_role;
create or replace function public.record_structured_qualification(p_actor_id uuid,p_organization_id uuid,p_lead_id uuid,p_field text,p_value text)returns jsonb language plpgsql security definer set search_path=''as $$declare p public.lead_qualification_profiles%rowtype;owner uuid;allowed text[];count_answered int;begin select assigned_to into owner from public.leads where id=p_lead_id and organization_id=p_organization_id;if owner is null or owner<>p_actor_id then raise exception'qualification_owner_only';end if;allowed:=case p_field when'purpose'then array['moradia','investimento','renda','revenda']when'timeline'then array['up_to_3_months','3_to_6_months','6_to_12_months','over_12_months']when'financing'then array['financing','own_resources','exchange','mixed']when'budget_readiness'then array['defined','approximate','unknown']when'region_readiness'then array['defined','flexible','unknown']when'unit_profile'then array['studio_1_bed','2_beds','3_plus_beds','indifferent']when'decision_role'then array['sole','joint','influencer','unknown']when'contact_preference'then array['whatsapp','phone','email','meeting']else null end;if allowed is null or not p_value=any(allowed)then raise exception'qualification_value_invalid';end if;perform pg_advisory_xact_lock(hashtextextended(p_organization_id::text||p_lead_id::text,0));insert into public.lead_qualification_profiles(organization_id,lead_id,broker_id)values(p_organization_id,p_lead_id,p_actor_id)on conflict(organization_id,lead_id)do nothing;select*into p from public.lead_qualification_profiles where organization_id=p_organization_id and lead_id=p_lead_id for update;if p.broker_id<>p_actor_id then raise exception'qualification_owner_mismatch';end if;execute format('update public.lead_qualification_profiles set %I=$1,version=version+1,updated_at=now() where id=$2',p_field||'_key')using p_value,p.id;select num_nonnulls(purpose_key,timeline_key,financing_key,budget_readiness_key,region_readiness_key,unit_profile_key,decision_role_key,contact_preference_key)into count_answered from public.lead_qualification_profiles where id=p.id;update public.lead_qualification_profiles set answered_count=count_answered,completed_at=case when count_answered=8 then coalesce(completed_at,now())else null end where id=p.id;insert into public.lead_qualification_events(organization_id,lead_id,profile_id,broker_id,changed_fields)values(p_organization_id,p_lead_id,p.id,p_actor_id,array[p_field]);if p_field='purpose'then update public.leads set purpose=p_value,updated_at=now()where id=p_lead_id and organization_id=p_organization_id;end if;return jsonb_build_object('profileId',p.id,'field',p_field,'value',p_value,'answered',count_answered,'total',8,'rawConversationStored',false);end$$;
create or replace function private.sync_qualification_owner()returns trigger language plpgsql security definer set search_path=''as $$begin if new.assigned_to is not null and new.assigned_to is distinct from old.assigned_to then update public.lead_qualification_profiles set broker_id=new.assigned_to,version=version+1,updated_at=now()where organization_id=new.organization_id and lead_id=new.id;end if;return new;end$$;drop trigger if exists sync_qualification_owner on public.leads;create trigger sync_qualification_owner after update of assigned_to on public.leads for each row execute function private.sync_qualification_owner();revoke all on function public.record_structured_qualification(uuid,uuid,uuid,text,text)from public,anon,authenticated;grant execute on function public.record_structured_qualification(uuid,uuid,uuid,text,text)to service_role;
update public.leads set metadata=metadata-'qualificationAnswers'where metadata?'qualificationAnswers';commit;
